class Solution:
    def diagonalSort(self, mat):
        from collections import defaultdict
        m, n = len(mat), len(mat[0])
        diags = defaultdict(list)
        for i in range(m):
            for j in range(n):
                diags[i - j].append(mat[i][j])
        for key in diags:
            diags[key].sort()
        result = [[0] * n for _ in range(m)]
        idx = defaultdict(int)
        for i in range(m):
            for j in range(n):
                k = i - j
                result[i][j] = diags[k][idx[k]]
                idx[k] += 1
        return result

