var diagonalSort = function(mat) {
    const m = mat.length, n = mat[0].length;
    const diags = new Map();
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            const k = i - j;
            if (!diags.has(k)) diags.set(k, []);
            diags.get(k).push(mat[i][j]);
        }
    }
    for (const [, arr] of diags) arr.sort((a, b) => a - b);
    const res = mat.map(r => r.slice());
    const idx = new Map();
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            const k = i - j;
            const pos = idx.get(k) || 0;
            res[i][j] = diags.get(k)[pos];
            idx.set(k, pos + 1);
        }
    }
    return res;
};
